& { $ErrorActionPreference='Continue'; $root=(Resolve-Path -LiteralPath (Get-Location).Path).Path.TrimEnd('\','/'); $skip='[\\/](\.git|node_modules|dist|build|\.next|\.vite|coverage|tmp|temp|\.vercel|\.wrangler)[\\/]'; $scanExt=@('.html','.css','.js','.mjs','.cjs','.jsx','.ts','.tsx','.json','.md'); $sb=[System.Text.StringBuilder]::new(); $all=Get-ChildItem -LiteralPath $root -Recurse -File -Force | Where-Object { $_.FullName -notmatch $skip } | Sort-Object FullName; $css=$all | Where-Object { $_.Extension.ToLowerInvariant() -eq '.css' }; $scan=$all | Where-Object { $scanExt -contains $_.Extension.ToLowerInvariant() }; [void]$sb.AppendLine('CSS AUDIT'); [void]$sb.AppendLine('ROOT: ' + $root); foreach($f in $css){ $rel=$f.FullName.Substring($root.Length).TrimStart('\','/'); [void]$sb.AppendLine(''); [void]$sb.AppendLine('FILE: ' + $rel); try { [void]$sb.AppendLine([System.IO.File]::ReadAllText($f.FullName,[System.Text.UTF8Encoding]::new($false))) } catch { [void]$sb.AppendLine('READ ERROR: ' + $_.Exception.Message) } }; [void]$sb.AppendLine(''); [void]$sb.AppendLine('CLASS MENTIONS'); $rx='(?i)(class(Name)?\s*=|classList\.|querySelector(All)?\(|getElementsByClassName\(|\.[_a-zA-Z-][_a-zA-Z0-9-]*)'; foreach($f in $scan){ $rel=$f.FullName.Substring($root.Length).TrimStart('\','/'); try { $lines=[System.IO.File]::ReadAllText($f.FullName,[System.Text.UTF8Encoding]::new($false)) -split "`r?`n" } catch { $lines=@() }; for($i=0;$i -lt $lines.Count;$i++){ $line=[string]$lines[$i]; if($line -match $rx){ [void]$sb.AppendLine($rel + ':' + ($i+1) + ' | ' + $line.Trim()) } } }; $result=$sb.ToString(); try { Set-Clipboard -Value $result } catch {}; Write-Host ('copied chars: ' + $result.Length); Write-Host ('css files copied: ' + $css.Count); Write-Host ('files scanned: ' + $scan.Count) }
